const deadlines = $input.all().map(i => {
  const d = i.json;
  const daysLeft = parseInt(d.days_left);
  let urgency;
  if (daysLeft <= 7) urgency = '🔴 KHẨN CẤP';
  else if (daysLeft <= 30) urgency = '🟡 SẮP ĐẾN';
  else urgency = '🟢 CÒN LÂU';

  return {
    ...d,
    days_left: daysLeft,
    urgency,
    deadline_formatted: new Date(d.deadline_date).toLocaleDateString('vi-VN'),
  };
});

return [{ json: {
  agent: 'calendar',
  deadlines,
  total: deadlines.length,
  next_deadline: deadlines[0] || null,
  disclaimer: 'Hạn nộp nếu trùng ngày nghỉ/lễ → chuyển sang ngày làm việc tiếp theo.'
} }];

// Handle free-form question about calendar/SOP
const message = $json.message || '';
const msg = message.toLowerCase();
const fs = require('fs');

let sopContent = '';
let platform = 'both';

if (msg.match(/etax|mobile/)) platform = 'etax';
else if (msg.match(/cổng thuế|canhan\.gdt/)) platform = 'portal';

try {
  sopContent = fs.readFileSync('/data/references/sop-quyet-toan.md', 'utf8');
} catch(e) { sopContent = 'Không thể đọc file SOP.'; }

let checklist = '';
try {
  const dl = fs.readFileSync('/data/references/deadline-tracker.md', 'utf8');
  checklist = dl;
} catch(e) {}

return [{ json: { message, platform, sopContent, checklist, user_type: $json.user_type } }];

